    public static class SamlResponse {
        private String responseId;
        private String issueInstant;
        private String issuer;
        private List<SamlAssertion> assertions;

        public String getResponseId() { return responseId; }
        public void setResponseId(String responseId) { this.responseId = responseId; }
        public String getIssueInstant() { return issueInstant; }
        public void setIssueInstant(String issueInstant) { this.issueInstant = issueInstant; }
        public String getIssuer() { return issuer; }
        public void setIssuer(String issuer) { this.issuer = issuer; }
        public List<SamlAssertion> getAssertions() { return assertions; }
        public void setAssertions(List<SamlAssertion> assertions) {
            this.assertions = Collections.unmodifiableList(assertions);
        }
    }

    public static class SamlAssertion {
        private String assertionId;
        private String issueInstant;
        private String issuer;
        private String nameId;
        private String nameIdFormat;
        private Map<String, List<String>> attributes;

        public String getAssertionId() { return assertionId; }
        public void setAssertionId(String assertionId) { this.assertionId = assertionId; }
        public String getIssueInstant() { return issueInstant; }
        public void setIssueInstant(String issueInstant) { this.issueInstant = issueInstant; }
        public String getIssuer() { return issuer; }
        public void setIssuer(String issuer) { this.issuer = issuer; }
        public String getNameId() { return nameId; }
        public void setNameId(String nameId) { this.nameId = nameId; }
        public String getNameIdFormat() { return nameIdFormat; }
        public void setNameIdFormat(String nameIdFormat) { this.nameIdFormat = nameIdFormat; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public void setAttributes(Map<String, List<String>> attributes) { this.attributes = attributes; }

        public String getAttributeValue(String name) {
            List<String> values = attributes != null ? attributes.get(name) : null;
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        public List<String> getAttributeValues(String name) {
            return attributes != null ? attributes.getOrDefault(name, Collections.emptyList()) : Collections.emptyList();
        }
    }

    public static class AuthenticatedSession {
        private final String sessionId;
        private final String principalName;
        private final String issuer;
        private final Map<String, List<String>> attributes;
        private final Instant createdAt;
        private final Instant expiresAt;

        public AuthenticatedSession(String sessionId, String principalName, String issuer,
                                    Map<String, List<String>> attributes, Instant createdAt, Instant expiresAt) {
            this.sessionId = sessionId;
            this.principalName = principalName;
            this.issuer = issuer;
            this.attributes = attributes != null ? Collections.unmodifiableMap(new LinkedHashMap<>(attributes)) : Collections.emptyMap();
            this.createdAt = createdAt;
            this.expiresAt = expiresAt;
        }

        public String getSessionId() { return sessionId; }
        public String getPrincipalName() { return principalName; }
        public String getIssuer() { return issuer; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public Instant getCreatedAt() { return createdAt; }
        public Instant getExpiresAt() { return expiresAt; }

        public boolean isExpired() {
            return Instant.now().isAfter(expiresAt);
        }

        public String getAttribute(String name) {
            List<String> values = attributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "AuthenticatedSession{" +
                    "sessionId='" + sessionId + '\'' +
                    ", principalName='" + principalName + '\'' +
                    ", issuer='" + issuer + '\'' +
                    ", createdAt=" + createdAt +
                    ", expiresAt=" + expiresAt +
                    '}';
        }
    }

    public static class SessionManager {
        private static final int SESSION_DURATION_MINUTES = 60;
        private static final int SESSION_ID_BYTES = 32;
        private final ConcurrentHashMap<String, AuthenticatedSession> activeSessions;
        private final SecureRandom secureRandom;

        public SessionManager() {
            this.activeSessions = new ConcurrentHashMap<>();
            this.secureRandom = new SecureRandom();
        }

        public AuthenticatedSession createSession(SamlResponse samlResponse) throws SamlProcessingException {
            if (samlResponse.getAssertions() == null || samlResponse.getAssertions().isEmpty()) {
                throw new SamlProcessingException("Cannot create session: no assertions available");
            }

            SamlAssertion primaryAssertion = samlResponse.getAssertions().get(0);

            String sessionId = generateSecureSessionId();
            Instant now = Instant.now();
            Instant expiresAt = now.plusSeconds(SESSION_DURATION_MINUTES * 60L);

            AuthenticatedSession session = new AuthenticatedSession(
                    sessionId,
                    primaryAssertion.getNameId(),
                    primaryAssertion.getIssuer(),
                    primaryAssertion.getAttributes(),
                    now,
                    expiresAt
            );

            activeSessions.put(sessionId, session);
            LOGGER.log(Level.INFO, "Created authenticated session for principal: {0}",
                    primaryAssertion.getNameId());

            return session;
        }

        public AuthenticatedSession getSession(String sessionId) {
            if (sessionId == null) return null;
            AuthenticatedSession session = activeSessions.get(sessionId);
            if (session != null && session.isExpired()) {
                invalidateSession(sessionId);
                return null;
            }
            return session;
        }

        public void invalidateSession(String sessionId) {
            if (sessionId != null) {
                AuthenticatedSession removed = activeSessions.remove(sessionId);
                if (removed != null) {
                    LOGGER.log(Level.INFO, "Invalidated session for principal: {0}",
                            removed.getPrincipalName());
                }
            }
        }

        public void cleanupExpiredSessions() {
            activeSessions.entrySet().removeIf(entry -> entry.getValue().isExpired());
        }

        private String generateSecureSessionId() {
            byte[] bytes = new byte[SESSION_ID_BYTES];
            secureRandom.nextBytes(bytes);
            return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        }
    }

    public static class SamlProcessingException extends Exception {
        public SamlProcessingException(String message) {
            super(message);
        }

        public SamlProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }

